record.field:
sql = """
CREATE OR REPLACE FUNCTION manual_library_increment_helpful(p_article_id INTEGER, p_is_helpful BOOLEAN) RETURNS VOID AS $$
BEGIN
    IF p_is_helpful THEN
        UPDATE knowledge_article SET helpful_count = COALESCE(helpful_count, 0) + 1 WHERE id = p_article_id;
    ELSE
        UPDATE knowledge_article SET unhelpful_count = COALESCE(unhelpful_count, 0) + 1 WHERE id = p_article_id;
    END IF;
END;
$$ LANGUAGE plpgsql;
"""
env.cr.execute(sql)
